const intake = $json.intake_result || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const manifestPathAbs = toContainerPath(intake.manifest_path);
const captionResultPathAbs = manifestPathAbs ? manifestPathAbs.replace(/manifest\.json$/, 'caption_result.json') : null;

return {
  json: {
    job_id: intake.job_id || null,
    manifest_path: manifestPathAbs,
    caption_result_path: captionResultPathAbs,
    intake_status: intake.status || null,
    platform_targets: intake.platform_targets || [],
    clip_path: intake.clip_path || null,
    eligible_for_caption: intake.status === 'ASSETS_VALID' && Boolean(manifestPathAbs) && Boolean(captionResultPathAbs),
    intake_result: intake
  }
};

const manifest = $json.manifest || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const rawPlatformTargets = Array.isArray(manifest.platform_targets) && manifest.platform_targets.length > 0 ? manifest.platform_targets : ($json.platform_targets || []);
const captionPlatformTargets = Array.from(new Set([...rawPlatformTargets, 'youtube_shorts']));

const clips = Array.isArray(manifest.clips) && manifest.clips.length > 0
  ? manifest.clips.map((clip, index) => {
    const clipPath = normalizeRepoPath(clip?.clip_path || clip?.file_path || '');
    return {
      clip_index: index + 1,
      clip_id: String(clip?.clip_id || 'clip_' + String(index + 1).padStart(2, '0')),
      file_name: String(clip?.file_name || (clipPath ? clipPath.split('/').pop() : '')),
      clip_path: clipPath,
      clip_path_abs: toContainerPath(clipPath),
    };
  })
  : [{
    clip_index: 1,
    clip_id: String(manifest.clip_id || 'clip_01'),
    file_name: String(normalizeRepoPath(manifest.clip_path) || '').split('/').pop(),
    clip_path: normalizeRepoPath(manifest.clip_path),
    clip_path_abs: toContainerPath(manifest.clip_path),
  }];

return {
  json: {
    ...$json,
    manifest,
    source_video_url: manifest.source_video_url || null,
    source_video_id: manifest.source_video_id || null,
    source_video_title: manifest.source_video_title || null,
    source_video_uploader: manifest.source_video_uploader || null,
    source_video_duration: manifest.source_video_duration || null,
    source_video_description: manifest.source_video_description || null,
    approval_mode: manifest.approval_mode || 'required',
    platform_targets: rawPlatformTargets,
    caption_platform_targets: captionPlatformTargets,
    upload_queue_targets: captionPlatformTargets.filter((platform) => ['youtube_shorts', 'facebook_reels'].includes(platform)),
    transcript_path_abs: toContainerPath(manifest.transcript_path),
    thumbnail_path_abs: toContainerPath(manifest.thumbnail_path),
    clip_path_abs: toContainerPath(manifest.clip_path),
    clips,
    clip_count: clips.length
  }
};

const binaryAvailable = Boolean($binary && Object.keys($binary).length > 0);
return {
  json: {
    ...$json,
    transcript_binary_available: binaryAvailable
  },
  binary: $binary
};

const defaults = {
  openai_caption_model: 'gpt-5.4-mini',
  openai_caption_language: 'id',
  openai_caption_brand_voice: 'ringkas, tajam, natural, tidak clickbait murahan',
  openai_caption_max_hashtags: '8'
};

let config = {};
let configError = null;
const binaryFieldName = $binary ? Object.keys($binary)[0] : null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const parsed = JSON.parse(rawBuffer.toString('utf8'));
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      config = parsed;
    } else {
      configError = 'Isi /files/config/caption_ai.json harus berupa object JSON.';
    }
  } catch (error) {
    configError = 'Config caption AI lokal tidak valid: ' + (error.message || 'parse gagal');
  }
}

return {
  json: {
    ...$json,
    caption_config_path: '/files/config/caption_ai.json',
    caption_config_error: configError,
    openai_api_key: String(config.openai_api_key || '').trim(),
    openai_caption_model: String(config.openai_caption_model || defaults.openai_caption_model),
    openai_caption_language: String(config.openai_caption_language || defaults.openai_caption_language),
    openai_caption_brand_voice: String(config.openai_caption_brand_voice || defaults.openai_caption_brand_voice),
    openai_caption_max_hashtags: String(config.openai_caption_max_hashtags || defaults.openai_caption_max_hashtags)
  }
};

const apiKey = String($json.openai_api_key || '').trim();
const model = String($json.openai_caption_model || 'gpt-5.4-mini');
const language = String($json.openai_caption_language || 'id');
const brandVoice = String($json.openai_caption_brand_voice || 'ringkas, tajam, natural, spesifik, tidak clickbait murahan');
const maxHashtags = Number.parseInt(String($json.openai_caption_max_hashtags || '8'), 10);
const transcriptText = String($json.transcript_text || '').trim();
const transcriptAvailable = transcriptText.length > 0;
const platformTargets = Array.isArray($json.platform_targets) ? $json.platform_targets : [];
const captionTargets = Array.isArray($json.caption_platform_targets) && $json.caption_platform_targets.length > 0 ? $json.caption_platform_targets : platformTargets;
const clips = Array.isArray($json.clips) && $json.clips.length > 0 ? $json.clips : [];
const sourceTitle = String($json.source_video_title || '').trim();
const sourceUploader = String($json.source_video_uploader || '').trim();
const sourceDescription = String($json.source_video_description || '').trim();

function buildFailure(message) {
  return {
    json: {
      ...$json,
      transcript_available: transcriptAvailable,
      caption_generation_status: 'failed',
      caption_error: message,
      caption_model: model
    }
  };
}

const configError = String($json.caption_config_error || '').trim();
if (configError) {
  return buildFailure(configError);
}

if (!apiKey) {
  return buildFailure('Konfigurasi OpenAI belum tersedia di /files/config/caption_ai.json atau openai_api_key kosong.');
}

const platformCaptionSchema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    platform: {
      type: 'string',
      enum: ['youtube_shorts', 'facebook_reels']
    },
    caption: { type: 'string' },
    hashtags: {
      type: 'array',
      items: { type: 'string' }
    }
  },
  required: ['platform', 'caption', 'hashtags']
};

const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    content_angle: { type: 'string' },
    hashtags: {
      type: 'array',
      items: { type: 'string' }
    },
    caption_pack: {
      type: 'array',
      items: platformCaptionSchema
    },
    clip_caption_pack: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          clip_id: { type: 'string' },
          clip_index: { type: 'number' },
          file_name: { type: 'string' },
          clip_path: { type: 'string' },
          captions: {
            type: 'array',
            items: platformCaptionSchema
          }
        },
        required: ['clip_id', 'clip_index', 'file_name', 'clip_path', 'captions']
      }
    }
  },
  required: ['content_angle', 'hashtags', 'caption_pack', 'clip_caption_pack']
};

const promptPayload = {
  language,
  brand_voice: brandVoice,
  max_hashtags: Number.isFinite(maxHashtags) ? maxHashtags : 8,
  platform_targets: captionTargets,
  approval_mode: $json.approval_mode || 'required',
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  source_video_title: sourceTitle || null,
  source_video_uploader: sourceUploader || null,
  source_video_duration: $json.source_video_duration || null,
  source_video_description: sourceDescription ? sourceDescription.slice(0, 3000) : null,
  clip_count: clips.length || $json.clip_count || 1,
  clips,
  transcript_available: transcriptAvailable,
  transcript_text: transcriptAvailable ? transcriptText.slice(0, 12000) : null
};

const body = {
  model,
  store: false,
  input: [
    {
      role: 'system',
      content: [
        {
          type: 'input_text',
          text: 'Anda adalah copywriter short-form content untuk creator automation. Balas hanya dengan JSON valid sesuai schema. Gunakan bahasa yang diminta. Buat caption yang relevan, natural, dan tidak generik. Wajib isi clip_caption_pack dengan jumlah item yang sama persis seperti clips input, urutan sama, clip_id sama, dan setiap item harus punya captions untuk setiap platform_targets. Jika transcript per clip tidak tersedia, buat variasi caption yang tetap spesifik terhadap source metadata dan nomor clip, jangan mengarang fakta yang tidak didukung. caption_pack adalah fallback global per platform; clip_caption_pack adalah sumber utama untuk upload queue.'
        }
      ]
    },
    {
      role: 'user',
      content: [
        {
          type: 'input_text',
          text: JSON.stringify(promptPayload, null, 2)
        }
      ]
    }
  ],
  text: {
    format: {
      type: 'json_schema',
      name: 'caption_result',
      strict: true,
      schema
    }
  }
};

try {
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/responses',
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + apiKey
    },
    body,
    json: true,
  });

  let parsed = data.output_parsed || null;
  let outputText = data.output_text || '';

  if (!parsed) {
    if (!outputText && Array.isArray(data.output)) {
      for (const item of data.output) {
        if (!Array.isArray(item.content)) continue;
        for (const part of item.content) {
          if (typeof part.text === 'string' && part.text.trim()) {
            outputText = part.text;
            break;
          }
        }
        if (outputText) break;
      }
    }

    if (!outputText) {
      return buildFailure('OpenAI tidak mengembalikan output_text yang bisa diparse.');
    }

    parsed = JSON.parse(outputText);
  }

  return {
    json: {
      ...$json,
      transcript_available: transcriptAvailable,
      caption_generation_status: 'generated',
      caption_model: model,
      caption_ai_result: parsed
    }
  };
} catch (error) {
  const responseBody = error?.response?.body;
  const responseText = typeof responseBody === 'string'
    ? responseBody
    : responseBody
      ? JSON.stringify(responseBody).slice(0, 800)
      : '';
  const suffix = responseText ? ' :: ' + responseText : '';
  return buildFailure((error.message || 'Gagal memanggil OpenAI Responses API.') + suffix);
}

const generatedAt = new Date().toISOString();
const ai = $json.caption_ai_result || {};
const clips = Array.isArray($json.clips) ? $json.clips : [];
const clipCaptionPack = Array.isArray(ai.clip_caption_pack) ? ai.clip_caption_pack : [];
const captionWarnings = [];

if (clips.length !== clipCaptionPack.length) {
  captionWarnings.push('clip_caption_pack count mismatch: clips=' + clips.length + ' captions=' + clipCaptionPack.length);
}

const result = {
  job_id: $json.job_id || null,
  stage: 'WF-02_GENERATE_CAPTION',
  status: 'CAPTION_GENERATED',
  generated_at: generatedAt,
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  source_video_title: $json.source_video_title || null,
  source_video_uploader: $json.source_video_uploader || null,
  platform_targets: $json.platform_targets || [],
  caption_platform_targets: $json.caption_platform_targets || $json.platform_targets || [],
  upload_queue_targets: $json.upload_queue_targets || [],
  approval_mode: $json.approval_mode || 'required',
  model: $json.caption_model || null,
  transcript_available: Boolean($json.transcript_available),
  clip_count: clips.length,
  clips,
  content_angle: ai.content_angle || null,
  hashtags: ai.hashtags || [],
  caption_pack: ai.caption_pack || [],
  clip_caption_pack: clipCaptionPack,
  caption_warnings: captionWarnings,
  next_stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS'
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    caption_result_status: result.status,
    caption_result_payload: result
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'caption_result.json'
    }
  }
};

const generatedAt = new Date().toISOString();
const result = {
  job_id: $json.job_id || null,
  stage: 'WF-02_GENERATE_CAPTION',
  status: 'CAPTION_FAILED',
  generated_at: generatedAt,
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  platform_targets: $json.platform_targets || [],
  approval_mode: $json.approval_mode || 'required',
  model: $json.caption_model || null,
  transcript_available: Boolean($json.transcript_available),
  error_message: $json.caption_error || 'Caption generation gagal tanpa detail.',
  next_stage: null
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    caption_result_status: result.status,
    caption_result_payload: result
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'caption_result.json'
    }
  }
};

const caption = $json.caption_result_payload || {};
const platform = String($json.upload_queue_platform || '').trim();

function csvCell(value) {
  const text = value === undefined || value === null ? '' : String(value);
  if (/[",\n\r]/.test(text)) {
    return '"' + text.replace(/"/g, '""') + '"';
  }
  return text;
}

function normalizeRepoPath(value) {
  if (!value) return '';
  const normalized = String(value).replace(/^\.\//, '').replace(/\\/g, '/');
  if (normalized.startsWith('/files/')) return 'shared/' + normalized.slice('/files/'.length);
  return normalized;
}

function normalizeHashtags(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => String(item || '').trim())
    .filter(Boolean)
    .map((tag) => tag.startsWith('#') ? tag : '#' + tag);
}

function findPlatformPack(packs, targetPlatform) {
  if (!Array.isArray(packs)) return null;
  return packs.find((pack) => pack && pack.platform === targetPlatform) || null;
}

function findClipPack(clip) {
  const clipPacks = Array.isArray(caption.clip_caption_pack) ? caption.clip_caption_pack : [];
  const clipId = String(clip.clip_id || '');
  const clipPath = normalizeRepoPath(clip.clip_path);
  const fileName = String(clip.file_name || (clipPath ? clipPath.split('/').pop() : ''));

  for (const item of clipPacks) {
    if (!item) continue;
    const itemClipPath = normalizeRepoPath(item.clip_path);
    const itemFileName = String(item.file_name || (itemClipPath ? itemClipPath.split('/').pop() : ''));
    const matched = String(item.clip_id || '') === clipId || itemClipPath === clipPath || itemFileName === fileName;
    if (!matched) continue;
    const pack = findPlatformPack(item.captions || item.caption_pack, platform);
    if (pack) return pack;
  }
  return null;
}

const clips = Array.isArray(caption.clips) && caption.clips.length > 0
  ? caption.clips
  : [{
    clip_index: 1,
    clip_id: 'clip_01',
    file_name: String(caption.clip_path || '').split('/').pop(),
    clip_path: caption.clip_path || '',
  }];
const fallbackPack = findPlatformPack(caption.caption_pack, platform) || (Array.isArray(caption.caption_pack) ? caption.caption_pack[0] : null) || {};
const baseWarning = String(caption.clip_caption_source || '') === 'generated_variant_from_global_metadata'
  ? 'caption unik dari metadata global; review singkat sebelum publish'
  : '';

const rows = clips.map((clip, index) => {
  const clipPath = normalizeRepoPath(clip.clip_path);
  const fileName = String(clip.file_name || (clipPath ? clipPath.split('/').pop() : ''));
  const clipPack = findClipPack(clip);
  const pack = clipPack || fallbackPack;
  const captionText = String(pack.caption || '').trim();
  const hashtags = normalizeHashtags(pack.hashtags || fallbackPack.hashtags || caption.hashtags);
  const hasClipCaption = Boolean(clipPack);
  const warning = !hasClipCaption
    ? 'caption fallback global; belum unik per clip'
    : baseWarning;
  const needsReview = Boolean(warning);
  return {
    job_id: caption.job_id || '',
    platform,
    clip_index: Number(clip.clip_index || index + 1),
    clip_id: String(clip.clip_id || 'clip_' + String(index + 1).padStart(2, '0')),
    file_name: fileName,
    clip_path: clipPath,
    file_exists: 'unknown_in_n8n',
    caption: captionText,
    hashtags: hashtags.join(' '),
    caption_full: [captionText, hashtags.join(' ')].filter(Boolean).join(' ').trim(),
    caption_source: hasClipCaption ? (caption.clip_caption_source || 'clip_caption_pack') : 'caption_pack_fallback',
    needs_review: String(needsReview),
    warning,
    upload_status: 'todo',
    published_url: '',
    notes: '',
  };
});

const headers = [
  'job_id',
  'platform',
  'clip_index',
  'clip_id',
  'file_name',
  'clip_path',
  'file_exists',
  'caption',
  'hashtags',
  'caption_full',
  'caption_source',
  'needs_review',
  'warning',
  'upload_status',
  'published_url',
  'notes',
];
const csv = [
  headers.join(','),
  ...rows.map((row) => headers.map((header) => csvCell(row[header])).join(',')),
].join('\n') + '\n';
const outputPath = String(caption.caption_result_path || '')
  .replace(/^shared\//, '/files/')
  .replace(/caption_result\.json$/, 'upload_queue_' + platform + '.csv');
const result = {
  platform,
  upload_queue_path: outputPath,
  upload_queue_path_repo: outputPath.replace(/^\/files\//, 'shared/'),
  upload_queue_rows: rows.length,
  upload_queue_rows_needing_review: rows.filter((row) => row.needs_review === 'true').length,
};

return {
  json: {
    ...$json,
    upload_queue_result: result,
  },
  binary: {
    data: {
      data: Buffer.from(csv, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: 'upload_queue_' + platform + '.csv',
    }
  }
};
